class Solution(object):
    def sumDigitDifferences(self, nums):
        n = len(nums)
        strs = [str(x) for x in nums]
        num_digits = len(strs[0])
        total = 0
        for pos in range(num_digits):
            freq = [0] * 10
            for s in strs:
                freq[int(s[pos])] += 1
            for c in freq:
                total += c * (n - c)
        # Each pair (i, j) with i < j is counted twice (once for i and once for j)
        return total // 2
